[Form]
public class DBMSQLQueryStorePlanWaitStats extends FormRun
{
    boolean queryGrouping;
    DBMQueryStoreStatGrouping currentGrouping = DBMQueryStoreStatGrouping::None;
    Map    waitStatsFields;
    Map    statsIntervalFields;
}

public void init()
{
    super();
    QueryBuildDataSource qbdsThis = this.queryBuildDataSource();
    qbdsThis.fields().dynamic(NoYes::No);
    SysDictTable dictTable = new SysDictTable(tableNum(DBMSQLQueryStoreWaitStats));
    SetEnumerator se = dictTable.fields(false,false,false,false).getEnumerator();
    waitStatsFields = new Map(Types::Integer, Types::Class);
    while (se.moveNext())
    {
        SysDictField dictField = se.current() as SysDictField;
        if (this.object(dictField.id()))
        {
            waitStatsFields.insert(dictField.id(), this.object(dictField.id()));
        }
    }
}

private void linkToParent()
{
    QueryBuildDataSource qbdsThis = this.queryBuildDataSource();
    if (element.args().dataSet() == tableNum(DBMSQLQueryStorePlanExt))
    {
        DBMSQLQueryStorePlanExt planExt = element.args().record() as DBMSQLQueryStorePlanExt;
        QueryBuildRange qbrPlanId = findOrCreateRange_W(qbdsThis,fieldNum(DBMSQLQueryStoreWaitStats, PlanId));
        qbrPlanId.value(queryValue(planExt.PlanId));

    }
    else 
    {
        if (element.args().dataSet() == tableNum(DBMSQLQueryStorePlan))
        {
            DBMSQLQueryStorePlan plan = element.args().record() as DBMSQLQueryStorePlan;
            QueryBuildRange qbrPlanId = findOrCreateRange_W(qbdsThis,fieldNum(DBMSQLQueryStoreWaitStats, PlanId));
            qbrPlanId.value(queryValue(plan.PlanId));
        }
    }

}

/// <summary>
///
/// </summary>
public void executeQuery()
{
    this.clearAll();
    this.setAggregateFields();
    this.setTimeGrouping();
    this.linkToParent();
    this.showAllAvailableFields();

    super();
}

private void showAllAvailableFields()
{
    MapEnumerator me;
    me = waitStatsFields.getEnumerator();
    while (me.moveNext())
    {
        FormDataObject fdo = me.currentValue() as FormDataObject;
        fdo.visible(false);
    }
    me = statsIntervalFields.getEnumerator();
    while (me.moveNext())
    {
        FormDataObject fdo = me.currentValue() as FormDataObject;
        fdo.visible(false);
    }
    QueryBuildDataSource qbdsWaitStats = DBMSQLQueryStoreWaitStats_ds.query().dataSourceTable(tableNum(DBMSQLQueryStoreWaitStats));
    for (int i = 1; i <= qbdsWaitStats.fields().fieldCount(); i++)
    {
        FieldId fieldId = qbdsWaitStats.fields().field(i);
        if (waitStatsFields.exists(fieldId))
        {
            FormDataObject fdo = waitStatsFields.lookup(qbdsWaitStats.fields().field(i)) as FormDataObject;
            if (fdo)
            {
                fdo.visible(true);
            }
        }

    }

    boolean groupByFieldAdded = false;
    for (int i = 1; i <= DBMSQLQueryStoreWaitStats_ds.query().groupByFieldCount(); i++)
    {
        QueryGroupByField  groupByField= DBMSQLQueryStoreWaitStats_ds.query().groupByField(i);

        QueryBuildDataSource qbdsGroupBy = groupByField.dataSource();
        if (qbdsGroupBy.table() == tableNum(DBMSQLQueryStoreRuntimeStatsInterval))
        {
            FormDataObject fdo = DBMSQLQueryStoreRuntimeStatsInterval_ds.object(groupByField.fieldId());
            if (fdo)
            {
                fdo.visible(true);
                groupByFieldAdded = true;
            }
        }
        if (qbdsGroupBy.table() == tableNum(DBMSQLQueryStoreWaitStats))
        {
            FormDataObject fdo = DBMSQLQueryStoreWaitStats_ds.object(groupByField.fieldId());
            if (fdo)
            {
                fdo.visible(true);
                groupByFieldAdded = true;
            }
        }

    }
    if (!groupByFieldAdded)
    {
        FormDataObject fdoStartTime = DBMSQLQueryStoreRuntimeStatsInterval_ds.object(fieldNum(DBMSQLQueryStoreRuntimeStatsInterval, startTime));
        fdoStartTime.visible(true);
        FormDataObject fdoEndTime = DBMSQLQueryStoreRuntimeStatsInterval_ds.object(fieldNum(DBMSQLQueryStoreRuntimeStatsInterval, endTime));
        fdoEndTime.visible(true);
    }
}

private void clearAll()
{
    this.query().clearAllFields();
    this.query().clearGroupBy();
    this.query().clearOrderBy();
}

private void setTimeGrouping()
{
    QueryBuildDataSource qbdsInterval= this.query().dataSourceTable(tableNum(DBMSQLQueryStoreRuntimeStatsInterval));
    FormDataSource formDataSource = DBMSQLQueryStoreWaitStats_ds;
    switch (currentGrouping)
    {
        case DBMQueryStoreStatGrouping::None:
            break;
        case DBMQueryStoreStatGrouping::Hour:
            qbdsInterval.addGroupByField(fieldNum(DBMSQLQueryStoreRuntimeStatsInterval, Hour));
            break;
        case DBMQueryStoreStatGrouping::Day:
            qbdsInterval.addGroupByField(fieldNum(DBMSQLQueryStoreRuntimeStatsInterval, Day));
            break;
        case DBMQueryStoreStatGrouping::Week:
            qbdsInterval.addGroupByField(fieldNum(DBMSQLQueryStoreRuntimeStatsInterval, Week));
            break;
        case DBMQueryStoreStatGrouping::Month:
            qbdsInterval.addGroupByField(fieldNum(DBMSQLQueryStoreRuntimeStatsInterval, Month));
            break;
    }   
}

private void setAggregateFields()
{
    boolean doGrouping = (currentGrouping!= DBMQueryStoreStatGrouping::None);
    QueryBuildDataSource qbdsWaitStats = this.query().dataSourceTable(tableNum(DBMSQLQueryStoreWaitStats));
    QueryBuildDataSource qbdsRuntimeStatsInterval = this.query().dataSourceTable(tableNum(DBMSQLQueryStoreRuntimeStatsInterval));
    if (doGrouping)
    {
        qbdsWaitStats.addSelectionField(fieldNum(DBMSQLQueryStoreWaitStats, AvgQueryWaitTimeMs), SelectionField::Avg);
        qbdsWaitStats.addSelectionField(fieldNum(DBMSQLQueryStoreWaitStats, TotalQueryWaitTimeMs), SelectionField::Sum);
        qbdsWaitStats.addSelectionField(fieldNum(DBMSQLQueryStoreWaitStats, MinQueryWaitTimeMs), SelectionField::Min);
        qbdsWaitStats.addSelectionField(fieldNum(DBMSQLQueryStoreWaitStats, MaxQueryWaitTimeMs), SelectionField::Max);
        qbdsWaitStats.addGroupByField(fieldNum(DBMSQLQueryStoreWaitStats, WaitCategory));
        qbdsWaitStats.addGroupByField(fieldNum(DBMSQLQueryStoreWaitStats, WaitCategoryDesc));
        qbdsWaitStats.addGroupByField(fieldNum(DBMSQLQueryStoreWaitStats, ExecutionType));
        qbdsWaitStats.addGroupByField(fieldNum(DBMSQLQueryStoreWaitStats, ExecutionTypeDesc));
        qbdsWaitStats.addGroupByField(fieldNum(DBMSQLQueryStoreWaitStats, replicaGroupId));
    }
    else
    {
        qbdsWaitStats.addAllFields(viewStr(DBMSQLQueryStoreWaitStats));
        qbdsRuntimeStatsInterval.addAllFields(viewStr(DBMSQLQueryStoreRuntimeStatsInterval));
    }
}

public void init()
{
    super();
    QueryBuildDataSource qbdsThis = this.queryBuildDataSource();
    qbdsThis.fields().dynamic(NoYes::No);
    qbdsThis.addLink(fieldNum(DBMSQLQueryStoreWaitStats, runtimeStatsIntervalId), fieldNum(DBMSQLQueryStoreRuntimeStatsInterval, runtimeStatsIntervalId));
    SysDictTable dictTable = new SysDictTable(tableNum(DBMSQLQueryStoreRuntimeStatsInterval));
    SetEnumerator se = dictTable.fields(false,false,false,false).getEnumerator();
    statsIntervalFields = new Map(Types::Integer, Types::Class);
    while (se.moveNext())
    {
        SysDictField dictField = se.current() as SysDictField;
        if (this.object(dictField.id()))
        {
            statsIntervalFields.insert(dictField.id(), this.object(dictField.id()));
        }
    }

}

public boolean modified()
{
    boolean ret;

    ret = super();
    currentGrouping = this.selection();
    DBMSQLQueryStoreWaitStats_ds.executeQuery();
    return ret;
}
